python3 -c "
import subprocess, sys

# G5: Secret scan
import re
SECRET_PATTERN = re.compile(
    r'(?:api[_-]?key|secret|password|token|credential|auth)\\s*[:=]\\s*[\"\\x27][A-Za-z0-9+/=_-]{16,}',
    re.IGNORECASE
)

issues = []
import pathlib
for f in pathlib.Path('.').rglob('*'):
    if f.is_symlink() or not f.is_file():
        continue
    if '.git/' in str(f) or 'node_modules/' in str(f):
        continue
    if f.suffix in ('.pyc', '.xml', '.png', '.jpg', '.gif', '.pdf', '.woff', '.woff2', '.ttf'):
        continue
    try:
        content = f.read_text(encoding='utf-8', errors='replace')
        for i, line in enumerate(content.splitlines(), 1):
            if SECRET_PATTERN.search(line):
                issues.append(f'{f}:{i}')
    except Exception:
        pass

if issues:
    print('SECRET SCAN: ISSUES FOUND')
    for i in issues:
        print(f'  {i}')
else:
    print('SECRET SCAN: PASS')
"
